import { useGameStore } from '../store/gameStore';

export default function Cashier() {
  const user = useGameStore((s) => s.user);
  if (!user) return <div className="loading">Загрузка...</div>;

  return (
    <div>
      <div className="header"><h1>Касса</h1></div>
      <div className="card cashier-card">
        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', fontWeight: 700, marginBottom: '0.5rem' }}>Ваш баланс</div>
        <div className="cashier-balance">{user.balance.toLocaleString()} ₽</div>
      </div>
      <div className="cashier-actions" style={{ marginBottom: '1.5rem' }}>
        <button className="btn btn-success" onClick={() => useGameStore.getState().showToast('Бонус +1000!', 'success')}>+ Пополнить</button>
        <button className="btn btn-secondary">- Вывести</button>
      </div>
      <div className="card">
        <h3>📊 Статистика</h3>
        <div style={{ marginTop: '0.75rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid var(--border)' }}>
            <span style={{ color: 'var(--text-secondary)', fontSize: '0.813rem' }}>Всего выиграно</span>
            <span style={{ color: 'var(--green)', fontWeight: 700 }}>0 ₽</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0' }}>
            <span style={{ color: 'var(--text-secondary)', fontSize: '0.813rem' }}>Чистый результат</span>
            <span style={{ color: 'var(--accent)', fontWeight: 700 }}>0 ₽</span>
          </div>
        </div>
      </div>
      <div className="card" style={{ marginTop: '0.75rem' }}>
        <h3>🎁 Ежедневный бонус</h3>
        <p style={{ fontSize: '0.813rem', color: 'var(--text-secondary)', marginBottom: '0.75rem' }}>Заходите каждый день и получайте бонус!</p>
        <button className="btn btn-small btn-primary" onClick={() => useGameStore.getState().showToast('+500 фишек!', 'success')}>Забрать 500 ₽</button>
      </div>
    </div>
  );
}
