import { useState, useEffect } from 'react';
import { useGameStore } from '../store/gameStore';

declare global {
  interface Window {
    Telegram?: {
      WebApp: {
        ready: () => void;
        expand: () => void;
        enableClosingConfirmation: () => void;
        initDataUnsafe: { user?: { id: number; first_name: string; last_name?: string; username?: string; language_code?: string } };
        initData: string;
        themeParams: Record<string, string>;
        HapticFeedback: { impactOccurred: (type: string) => void };
        close: () => void;
      };
    };
  }
}

export function useTelegramAuth() {
  const [loading, setLoading] = useState(true);
  const setUser = useGameStore((s) => s.setUser);

  useEffect(() => {
    const tg = window.Telegram?.WebApp;

    if (tg) {
      tg.ready();
      tg.expand();
    }

    const tgUser = tg?.initDataUnsafe?.user;

    const balance = parseInt(localStorage.getItem('pokerok_balance') || '10000', 10);
    const games = parseInt(localStorage.getItem('pokerok_games') || '0', 10);
    const wins = parseInt(localStorage.getItem('pokerok_wins') || '0', 10);

    setUser({
      id: String(tgUser?.id || Math.floor(Math.random() * 999999)),
      firstName: tgUser?.first_name || 'Игрок',
      lastName: tgUser?.last_name,
      username: tgUser?.username,
      balance,
      gamesPlayed: games,
      gamesWon: wins,
      elo: 1200,
    });

    setLoading(false);
  }, []);

  return { loading, error: null };
}
