import { useState } from 'react';
import { useTelegramAuth } from './hooks/useTelegramAuth';
import { useGameStore } from './store/gameStore';
import Lobby from './pages/Lobby';
import BotGame from './pages/BotGame';
import Multiplayer from './pages/Multiplayer';
import Profile from './pages/Profile';
import Cashier from './pages/Cashier';

export default function App() {
  const { loading, error } = useTelegramAuth();
  const [activeTab, setActiveTab] = useState('lobby');
  const currentTable = useGameStore((s) => s.currentTable);
  const toast = useGameStore((s) => s.toast);

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>♠</div>
          <p style={{ color: 'var(--text-muted)' }}>Загрузка PokerOK...</p>
        </div>
      </div>
    );
  }

  if (currentTable === 'bot') {
    return (
      <>
        <BotGame />
        {toast && <div className="toast-container"><div className={`toast ${toast.type}`}>{toast.message}</div></div>}
      </>
    );
  }

  if (currentTable === 'multi') {
    return (
      <>
        <Multiplayer />
        {toast && <div className="toast-container"><div className={`toast ${toast.type}`}>{toast.message}</div></div>}
      </>
    );
  }

  return (
    <div className="app-container">
      {activeTab === 'lobby' && <Lobby />}
      {activeTab === 'profile' && <Profile />}
      {activeTab === 'cashier' && <Cashier />}

      <nav className="bottom-nav">
        <button className={`nav-item ${activeTab === 'lobby' ? 'active' : ''}`} onClick={() => setActiveTab('lobby')}>
          <span className="nav-icon">🎰</span><span>Лобби</span>
        </button>
        <button className={`nav-item ${activeTab === 'profile' ? 'active' : ''}`} onClick={() => setActiveTab('profile')}>
          <span className="nav-icon">👤</span><span>Профиль</span>
        </button>
        <button className={`nav-item ${activeTab === 'cashier' ? 'active' : ''}`} onClick={() => setActiveTab('cashier')}>
          <span className="nav-icon">💰</span><span>Касса</span>
        </button>
      </nav>

      {toast && <div className="toast-container"><div className={`toast ${toast.type}`}>{toast.message}</div></div>}
    </div>
  );
}
