import { useGameStore } from '../store/gameStore';

export default function Profile() {
  const user = useGameStore((s) => s.user);
  if (!user) return <div className="loading">Загрузка...</div>;

  const initials = (user.firstName[0] + (user.lastName?.[0] || '')).toUpperCase();
  const winRate = user.gamesPlayed > 0 ? Math.round((user.gamesWon / user.gamesPlayed) * 100) : 0;

  return (
    <div>
      <div className="header"><h1>Профиль</h1></div>
      <div className="card profile-card">
        <div className="profile-avatar">{initials}</div>
        <div className="profile-name">{user.firstName} {user.lastName || ''}</div>
        {user.username && <div style={{ color: 'var(--text-muted)', fontSize: '0.813rem' }}>@{user.username}</div>}
      </div>
      <div className="profile-stats">
        <div className="profile-stat"><div className="stat-value">{user.balance.toLocaleString()}</div><div className="stat-label">Баланс</div></div>
        <div className="profile-stat"><div className="stat-value">{user.gamesPlayed}</div><div className="stat-label">Игр</div></div>
        <div className="profile-stat"><div className="stat-value">{user.elo}</div><div className="stat-label">Рейтинг</div></div>
      </div>
      <div className="profile-stats" style={{ marginTop: '0.5rem' }}>
        <div className="profile-stat"><div className="stat-value" style={{ color: 'var(--green)' }}>{winRate}%</div><div className="stat-label">Винрейт</div></div>
        <div className="profile-stat"><div className="stat-value" style={{ color: 'var(--green)' }}>{user.gamesWon}</div><div className="stat-label">Побед</div></div>
        <div className="profile-stat"><div className="stat-value" style={{ color: 'var(--red)' }}>{user.gamesPlayed - user.gamesWon}</div><div className="stat-label">Поражений</div></div>
      </div>
      <div style={{ marginTop: '1.5rem' }}>
        <div className="card">
          <h3>🏆 Достижения</h3>
          <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginTop: '0.75rem' }}>
            <div style={{ background: 'var(--bg-elevated)', borderRadius: '0.5rem', padding: '0.5rem 0.75rem', fontSize: '0.75rem' }}>🎰 Первая игра</div>
            <div style={{ background: 'var(--bg-elevated)', borderRadius: '0.5rem', padding: '0.5rem 0.75rem', fontSize: '0.75rem', opacity: 0.4 }}>🔒 10 побед</div>
            <div style={{ background: 'var(--bg-elevated)', borderRadius: '0.5rem', padding: '0.5rem 0.75rem', fontSize: '0.75rem', opacity: 0.4 }}>🔒 Роял-флеш</div>
          </div>
        </div>
      </div>
    </div>
  );
}
