import { initializeApp } from 'firebase/app';
import { getDatabase, ref, set, update, onValue, get, child, remove } from 'firebase/database';

const firebaseConfig = {
  apiKey: "AIzaSyD23mI1TenrAjE5SVlef5t2JL8BLk-t3yc",
  authDomain: "pokerok.firebaseapp.com",
  databaseURL: "https://pokerok-default-rtdb.europe-west1.firebasedatabase.app",
  projectId: "pokerok",
  storageBucket: "pokerok.firebasestorage.app",
  messagingSenderId: "935793193353",
  appId: "1:935793193353:web:421e2c8bb1ef8c8bb33158",
};

let db: any = null;
function getDB() {
  if (!db) {
    try {
      const app = initializeApp(firebaseConfig);
      db = getDatabase(app);
    } catch(e) { console.error('Firebase init failed:', e); }
  }
  return db;
}

export async function createRoom(hostId: string, hostName: string): Promise<string> {
  const d = getDB();
  if (!d) return '';
  const roomId = Math.random().toString(36).substring(2, 8).toUpperCase();
  await set(ref(d, `rooms/${roomId}`), {
    host: { id: hostId, name: hostName },
    guest: null,
    state: 'waiting',
    hostReady: false,
    guestReady: false,
    game: null,
    createdAt: Date.now(),
  });
  return roomId;
}

export async function joinRoom(roomId: string, guestId: string, guestName: string) {
  const d = getDB();
  if (!d) return null;
  const snap = await get(child(ref(d), `rooms/${roomId}`));
  if (!snap.exists()) return null;
  const room = snap.val();
  if (room.guest) return null;
  await update(ref(d, `rooms/${roomId}`), {
    guest: { id: guestId, name: guestName },
    state: 'connected',
  });
  return room;
}

export async function setReadyState(roomId: string, isHost: boolean) {
  const d = getDB();
  if (!d) return;
  update(ref(d, `rooms/${roomId}`), {
    [isHost ? 'hostReady' : 'guestReady']: true,
    state: 'ready',
  });
}

export function pushGame(roomId: string, gs: any) {
  const d = getDB();
  if (!d) return;
  set(ref(d, `rooms/${roomId}/game`), gs);
}

export function pushRoomData(roomId: string, data: any) {
  const d = getDB();
  if (!d) return;
  update(ref(d, `rooms/${roomId}`), data);
}

export function onRoomChange(roomId: string, cb: (data: any) => void) {
  const d = getDB();
  if (!d) return () => {};
  return onValue(ref(d, `rooms/${roomId}`), (snap: any) => {
    if (snap.exists()) cb(snap.val());
  });
}

export function onGameChange(roomId: string, cb: (gs: any) => void) {
  const d = getDB();
  if (!d) return () => {};
  return onValue(ref(d, `rooms/${roomId}/game`), (snap: any) => {
    if (snap.exists()) cb(snap.val());
  });
}

export async function getRoom(roomId: string) {
  const d = getDB();
  if (!d) return null;
  try {
    const snap = await get(child(ref(d), `rooms/${roomId}`));
    return snap.exists() ? snap.val() : null;
  } catch { return null; }
}

export function cleanup(roomId: string) {
  const d = getDB();
  if (!d) return;
  try { remove(ref(d, `rooms/${roomId}`)); } catch {}
}
