import { useState, useEffect, useCallback } from 'react';
import { useGameStore } from '../store/gameStore';

const TABLES = [
  { id: 'nl2', name: 'NL2 Hold\'em', smallBlind: 1, bigBlind: 2, buyin: 200, players: 3, maxPlayers: 6, type: 'Кэш' },
  { id: 'nl5', name: 'NL5 Hold\'em', smallBlind: 2, bigBlind: 5, buyin: 500, players: 1, maxPlayers: 6, type: 'Кэш' },
  { id: 'nl10', name: 'NL10 Hold\'em', smallBlind: 5, bigBlind: 10, buyin: 1000, players: 5, maxPlayers: 9, type: 'Кэш' },
  { id: 'sng1', name: 'Sit & Go $50', smallBlind: 10, bigBlind: 20, buyin: 50, players: 4, maxPlayers: 6, type: 'Турнир' },
];

export default function Lobby() {
  const user = useGameStore((s) => s.user);
  const showToast = useGameStore((s) => s.showToast);
  const [bonusClaimed, setBonusClaimed] = useState(() => localStorage.getItem('pokerok_bonus') === 'true');

  const handleBonus = () => {
    if (bonusClaimed) return;
    setBonusClaimed(true);
    localStorage.setItem('pokerok_bonus', 'true');
    showToast('+10,000 фишек!', 'success');
  };

  return (
    <div>
      <div className="header">
        <h1>♠ PokerOK</h1>
        <div className="balance-badge">
          💰 {user?.balance?.toLocaleString() || 10000}
        </div>
      </div>

      <div className="lobby-header">
        <h2>Привет, {user?.firstName || 'Игрок'}! 👋</h2>
        <p>Выбери стол или сыграй с ботом</p>
      </div>

      {/* Bot game button */}
      <div className="card" style={{ background: 'linear-gradient(135deg, #1e3a5f 0%, #0f2440 100%)', borderColor: '#3b82f6', marginBottom: '1rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h3 style={{ color: '#60a5fa', marginBottom: '0.25rem' }}>🤖 Игра с ботом</h3>
            <p style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Техасский Холдем 1 на 1</p>
          </div>
          <button className="btn btn-small" style={{ background: '#3b82f6', color: '#fff' }} onClick={() => { useGameStore.getState().setCurrentTable('bot'); }}>
            Играть
          </button>
        </div>
      </div>

      <div className="card" style={{ background: 'linear-gradient(135deg, #1a3a1e 0%, #0f2414 100%)', borderColor: '#22c55e', marginBottom: '1rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h3 style={{ color: '#4ade80', marginBottom: '0.25rem' }}>👥 Игра с другом</h3>
            <p style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Создай комнату и пригласи</p>
          </div>
          <button className="btn btn-small" style={{ background: '#22c55e', color: '#000' }} onClick={() => { useGameStore.getState().setCurrentTable('multi'); }}>
            Играть
          </button>
        </div>
      </div>

      <h3 style={{ fontSize: '0.813rem', fontWeight: 700, marginBottom: '0.75rem', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
        Столы
      </h3>

      {TABLES.map((table) => (
        <div key={table.id} className="table-item">
          <div className="table-info">
            <h4>{table.name}</h4>
            <p>{table.type} · Блайнды: {table.smallBlind}/{table.bigBlind} · Бай-ин: {table.buyin}</p>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <span style={{ fontSize: '0.813rem', fontWeight: 600, color: table.players < table.maxPlayers ? 'var(--green)' : 'var(--red)' }}>
              {table.players}/{table.maxPlayers}
            </span>
            <button className="btn btn-small btn-primary" style={{ width: 'auto', padding: '0.375rem 0.75rem' }} onClick={() => showToast('Скоро!', 'info')}>
              Сесть
            </button>
          </div>
        </div>
      ))}

      {/* Bonus */}
      <div className="card" style={{ marginTop: '1.5rem', background: bonusClaimed ? 'var(--green-bg)' : 'var(--bg-card)', borderColor: bonusClaimed ? 'var(--green)' : 'var(--accent)' }}>
        <h3 style={{ color: bonusClaimed ? 'var(--green)' : 'var(--accent)' }}>
          {bonusClaimed ? '✅ Бонус получен!' : '🎁 Бонус новичка'}
        </h3>
        <p style={{ fontSize: '0.813rem', color: 'var(--text-secondary)', marginBottom: '0.75rem' }}>
          {bonusClaimed ? 'Вы получили 10,000 фишек' : 'Получите 10,000 бесплатных фишек!'}
        </p>
        {!bonusClaimed && (
          <button className="btn btn-small btn-primary" onClick={handleBonus}>
            Забрать 10,000
          </button>
        )}
      </div>
    </div>
  );
}
